     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
     5→import { useSearchParams } from "next/navigation";
     6→import { useCamera } from "@/hooks/useCamera";
     7→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     8→import { useMemojiAvatar } from "@/hooks/useMemojiAvatar";
     9→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
    10→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    11→import AvatarPiP from "@/components/mirror/AvatarPiP";
    12→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    13→import ProductCarousel, {
    14→  type ProductCard,
    15→} from "@/components/mirror/ProductCarousel";
    16→import { SentenceBuffer } from "@/lib/sentence-buffer";
    17→import { findScriptedResponse, detectEmotion } from "@/lib/scripted-responses";
    18→import { socket } from "@/lib/socket";
    19→import type { DetectedGesture, GestureType } from "@/types/gestures";
    20→import type { RecommendationResponse, Outfit } from "@/lib/types";
    21→
    22→export default function MirrorPageWrapper() {
    23→  return (
    24→    <Suspense fallback={null}>
    25→      <MirrorPage />
    26→    </Suspense>
    27→  );
    28→}
    29→
    30→function MirrorPage() {
    31→  const searchParams = useSearchParams();
    32→  const userId = searchParams.get("user_id");
    33→
    34→  // Camera + gesture recognition
    35→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    36→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    37→  const gestureKeyRef = useRef(0);
    38→  const [gestureKey, setGestureKey] = useState(0);
    39→
    40→  // Session state
    41→  const [sessionActive, setSessionActive] = useState(false);
    42→  const [isStarting, setIsStarting] = useState(false);
    43→  const [products, setProducts] = useState<ProductCard[]>([]);
    44→
    45→  // Recommendation state (from main)
    46→  const [outfitData, setOutfitData] = useState<RecommendationResponse["data"] | null>(null);
    47→  const [outfitActiveIndex, setOutfitActiveIndex] = useState(0);
    48→  const outfits = outfitData?.outfits ?? [];
    49→
    50→  // Avatar + voice
    51→  const avatar = useMemojiAvatar();
    52→  const stt = useDeepgramSTT();
    53→
    54→  // Queue transcripts while avatar is speaking, send when quiet
    55→  const pendingTranscriptRef = useRef<string | null>(null);
    56→
    57→  // Accumulate full response text before deciding delivery method
    58→  const responseAccumulatorRef = useRef<string>("");
    59→
    60→  // Sentence buffer: used for non-scripted responses (TTS path)
    61→  const sentenceBuffer = useMemo(
    62→    () =>
    63→      new SentenceBuffer((sentence) => {
    64→        avatar.speak(sentence);
    65→      }),
    66→    // eslint-disable-next-line react-hooks/exhaustive-deps
    67→    [avatar.speak],
    68→  );
    69→
    70→  // Auto-advance outfit carousel
    71→  useEffect(() => {
    72→    if (outfits.length <= 1) return;
    73→    const timer = setInterval(() => {
    74→      setOutfitActiveIndex((i) => (i + 1) % outfits.length);
    75→    }, 8000);
    76→    return () => clearInterval(timer);
    77→  }, [outfits.length]);
    78→
    79→  // Connect socket and join user room
    80→  useEffect(() => {
    81→    socket.connect();
    82→
    83→    if (userId) {
    84→      socket.emit("join_room", { user_id: userId });
    85→    }
    86→
    87→    // Recommendation events (from main)
    88→    socket.on("outfits_ready", (result: RecommendationResponse) => {
    89→      if (result.status === "success" && result.data) {
    90→        setOutfitData(result.data);
    91→        setOutfitActiveIndex(0);
    92→      }
    93→    });
    94→
    95→    return () => {
    96→      socket.off("outfits_ready");
    97→      socket.disconnect();
    98→    };
    99→  }, [userId]);
   100→
   101→  // Listen for session_active from backend
   102→  useEffect(() => {
   103→    const handleSessionActive = () => {
   104→      setSessionActive(true);
   105→      setIsStarting(false);
   106→      avatar.startSession();
   107→      stt.startListening();
   108→    };
   109→
   110→    socket.on("session_active", handleSessionActive);
   111→    return () => {
   112→      socket.off("session_active", handleSessionActive);
   113→    };
   114→    // eslint-disable-next-line react-hooks/exhaustive-deps
   115→  }, []);
   116→
   117→  // Listen for mira_speech events (streamed text from AI)
   118→  useEffect(() => {
   119→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   120→      // Fallback session detection
   121→      if (!sessionActive && !isStarting) {
   122→        setSessionActive(true);
   123→        setIsStarting(false);
   124→        avatar.startSession();
   125→        stt.startListening();
   126→      }
   127→
   128→      if (!data.text) return;
   129→
   130→      if (data.is_chunk !== false) {
   131→        // Still accumulating — show thinking state for visual feedback
   132→        responseAccumulatorRef.current += data.text;
   133→        avatar.setAvatarState("thinking");
   134→      } else {
   135→        // End of message — accumulate final chunk, then deliver
   136→        responseAccumulatorRef.current += data.text;
   137→        const fullText = responseAccumulatorRef.current;
   138→        responseAccumulatorRef.current = "";
   139→
   140→        // Check for scripted response match
   141→        const scripted = findScriptedResponse(fullText);
   142→
   143→        if (scripted) {
   144→          // Play pre-recorded video with baked-in audio (perfect lip sync)
   145→          console.log("[Mirror] Scripted match:", scripted.phrase);
   146→          avatar.playScripted(scripted.video);
   147→        } else {
   148→          // No match — detect emotion for avatar state, then TTS per sentence
   149→          const emotion = detectEmotion(fullText);
   150→          avatar.setAvatarState(emotion);
   151→
   152→          // Feed full text through sentence buffer for per-sentence TTS
   153→          sentenceBuffer.feed(fullText);
   154→          sentenceBuffer.flush();
   155→        }
   156→      }
   157→    };
   158→
   159→    socket.on("mira_speech", handleSpeech);
   160→    return () => {
   161→      socket.off("mira_speech", handleSpeech);
   162→    };
   163→    // eslint-disable-next-line react-hooks/exhaustive-deps
   164→  }, [sessionActive, isStarting, sentenceBuffer]);
   165→
   166→  // Listen for tool_result events (product recommendations)
   167→  useEffect(() => {
   168→    const handleToolResult = (data: { tool?: string; items?: ProductCard[] }) => {
   169→      if (data.tool === "present_items" && data.items) {
   170→        setProducts(data.items);
   171→      }
   172→    };
   173→
   174→    socket.on("tool_result", handleToolResult);
   175→    return () => {
   176→      socket.off("tool_result", handleToolResult);
   177→    };
   178→  }, []);
   179→
   180→  // Listen for session_ended
   181→  useEffect(() => {
   182→    const handleSessionEnded = () => {
   183→      avatar.stopSession();
   184→      stt.stopListening();
   185→      setSessionActive(false);
   186→      setProducts([]);
   187→    };
   188→
   189→    socket.on("session_ended", handleSessionEnded);
   190→    return () => {
   191→      socket.off("session_ended", handleSessionEnded);
   192→    };
   193→    // eslint-disable-next-line react-hooks/exhaustive-deps
   194→  }, []);
   195→
   196→  // Send transcripts to backend when avatar stops speaking
   197→  useEffect(() => {
   198→    if (!avatar.isSpeaking && pendingTranscriptRef.current && userId) {
   199→      socket.emit("mirror_event", {
   200→        user_id: userId,
   201→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   202→      });
   203→      pendingTranscriptRef.current = null;
   204→    }
   205→  }, [avatar.isSpeaking, userId]);
   206→
   207→  // Forward final STT transcripts
   208→  useEffect(() => {
   209→    if (!stt.transcript || !userId) return;
   210→
   211→    if (avatar.isSpeaking) {
   212→      pendingTranscriptRef.current = stt.transcript;
   213→    } else {
   214→      socket.emit("mirror_event", {
   215→        user_id: userId,
   216→        event: { type: "voice", transcript: stt.transcript },
   217→      });
   218→    }
   219→    // eslint-disable-next-line react-hooks/exhaustive-deps
   220→  }, [stt.transcript, userId]);
   221→
   222→  // Listen for snapshot requests from the backend
   223→  useEffect(() => {
   224→    const handleSnapshotRequest = () => {
   225→      const video = videoRef.current;
   226→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   227→
   228→      const canvas = document.createElement("canvas");
   229→      canvas.width = video.videoWidth;
   230→      canvas.height = video.videoHeight;
   231→      const ctx = canvas.getContext("2d");
   232→      if (!ctx) return;
   233→
   234→      ctx.drawImage(video, 0, 0);
   235→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   236→      const base64 = dataUrl.split(",")[1];
   237→
   238→      socket.emit("mirror_event", {
   239→        type: "snapshot",
   240→        image_base64: base64,
   241→        user_id: userId,
   242→      });
   243→    };
   244→
   245→    socket.on("request_snapshot", handleSnapshotRequest);
   246→    return () => {
   247→      socket.off("request_snapshot", handleSnapshotRequest);
   248→    };
   249→  }, [videoRef, userId]);
   250→
   251→  // Gesture handler
   252→  const handleGesture = useCallback(
   253→    (gesture: DetectedGesture) => {
   254→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   255→
   256→      setLastGesture(gesture.type);
   257→      gestureKeyRef.current += 1;
   258→      setGestureKey(gestureKeyRef.current);
   259→
   260→      // Forward to carousel if it exists
   261→      const carouselGesture = (
   262→        window as unknown as Record<string, unknown>
   263→      ).__carouselGesture as ((g: GestureType) => void) | undefined;
   264→      if (carouselGesture) {
   265→        carouselGesture(gesture.type);
   266→      }
   267→
   268→      socket.emit("mirror_event", {
   269→        user_id: userId,
   270→        event: {
   271→          type: "gesture",
   272→          gesture: gesture.type,
   273→          confidence: gesture.confidence,
   274→          timestamp: gesture.timestamp,
   275→        },
   276→      });
   277→    },
   278→    [userId],
   279→  );
   280→
   281→  const { isLoading: isModelLoading, error: modelError } =
   282→    useGestureRecognizer({
   283→      videoRef,
   284→      isVideoReady: isCameraReady,
   285→      onGesture: handleGesture,
   286→    });
   287→
   288→  const handleProductGesture = useCallback(
   289→    (gesture: GestureType, item: ProductCard) => {
   290→      socket.emit("mirror_event", {
   291→        user_id: userId,
   292→        event: {
   293→          type: "product_gesture",
   294→          gesture,
   295→          product_id: item.product_id,
   296→          title: item.title,
   297→        },
   298→      });
   299→    },
   300→    [userId],
   301→  );
   302→
   303→  const handleStartSession = useCallback(() => {
   304→    if (!userId || isStarting || sessionActive) return;
   305→
   306→    // Unlock browser audio policy while we still have the user gesture context
   307→    const ctx = new AudioContext();
   308→    ctx.resume().then(() => ctx.close());
   309→
   310→    setIsStarting(true);
   311→    socket.emit("start_session", { user_id: userId });
   312→  }, [userId, isStarting, sessionActive]);
   313→
   314→  return (
   315→    <main
   316→      style={{
   317→        position: "relative",
   318→        width: "100vw",
   319→        height: "100vh",
   320→        background: "#000",
   321→        overflow: "hidden",
   322→      }}
   323→    >
   324→      {/* Webcam feed (mirrored) */}
   325→      <video
   326→        ref={videoRef}
   327→        autoPlay
   328→        playsInline
   329→        muted
   330→        style={{
   331→          position: "absolute",
   332→          top: 0,
   333→          left: 0,
   334→          width: "100%",
   335→          height: "100%",
   336→          objectFit: "cover",
   337→          transform: "scaleX(-1)",
   338→        }}
   339→      />
   340→
   341→      {/* Start Session button (pre-session overlay) */}
   342→      {!sessionActive && !isStarting && (
   343→        <div
   344→          style={{
   345→            position: "absolute",
   346→            top: "50%",
   347→            left: "50%",
   348→            transform: "translate(-50%, -50%)",
   349→            zIndex: 20,
   350→          }}
   351→        >
   352→          <button
   353→            onClick={handleStartSession}
   354→            style={{
   355→              padding: "16px 40px",
   356→              fontSize: "1.3rem",
   357→              fontWeight: 600,
   358→              color: "#fff",
   359→              background: "rgba(100, 140, 255, 0.8)",
   360→              border: "none",
   361→              borderRadius: 12,
   362→              cursor: "pointer",
   363→              backdropFilter: "blur(10px)",
   364→              boxShadow: "0 4px 20px rgba(100, 140, 255, 0.4)",
   365→            }}
   366→          >
   367→            Start Session
   368→          </button>
   369→        </div>
   370→      )}
   371→
   372→      {/* Starting indicator */}
   373→      {isStarting && (
   374→        <div
   375→          style={{
   376→            position: "absolute",
   377→            top: "50%",
   378→            left: "50%",
   379→            transform: "translate(-50%, -50%)",
   380→            color: "#fff",
   381→            fontSize: "1.5rem",
   382→            zIndex: 20,
   383→          }}
   384→        >
   385→          Starting...
   386→        </div>
   387→      )}
   388→
   389→      {/* Avatar PiP (top-right, session only) */}
   390→      {sessionActive && (
   391→        <AvatarPiP containerRef={avatar.containerRef} isReady={avatar.isReady} />
   392→      )}
   393→
   394→      {/* Gesture visual feedback */}
   395→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   396→
   397→      {/* Product carousel (bottom, when products exist) */}
   398→      {sessionActive && products.length > 0 && (
   399→        <ProductCarousel items={products} onGesture={handleProductGesture} />
   400→      )}
   401→
   402→      {/* Outfit recommendation overlay (from recommendation pipeline) */}
   403→      {outfitData && outfits.length > 0 && (
   404→        <div
   405→          style={{
   406→            position: "absolute",
   407→            bottom: 0,
   408→            left: 0,
   409→            right: 0,
   410→            zIndex: 15,
   411→            pointerEvents: "none",
   412→          }}
   413→        >
   414→          <OutfitsView
   415→            greeting={outfitData.greeting}
   416→            styleAnalysis={outfitData.style_analysis}
   417→            outfits={outfits}
   418→            activeIndex={outfitActiveIndex}
   419→            onDotClick={setOutfitActiveIndex}
   420→          />
   421→        </div>
   422→      )}
   423→
   424→      {/* Voice indicator (bottom-left, session only) */}
   425→      {sessionActive && (
   426→        <VoiceIndicator
   427→          isListening={stt.isListening}
   428→          interimTranscript={stt.interimTranscript}
   429→        />
   430→      )}
   431→
   432→      {/* Error indicators */}
   433→      {(cameraError || modelError) && (
   434→        <div
   435→          style={{
   436→            position: "absolute",
   437→            bottom: 20,
   438→            left: 20,
   439→            color: "#f44",
   440→            fontSize: "1rem",
   441→            zIndex: 30,
   442→          }}
   443→        >
   444→          {cameraError && <div>Camera: {cameraError}</div>}
   445→          {modelError && <div>Model: {modelError}</div>}
   446→        </div>
   447→      )}
   448→
   449→      {isModelLoading && (
   450→        <div
   451→          style={{
   452→            position: "absolute",
   453→            top: "50%",
   454→            left: "50%",
   455→            transform: "translate(-50%, -50%)",
   456→            color: "#fff",
   457→            fontSize: "1.5rem",
   458→            zIndex: 30,
   459→            pointerEvents: "none",
   460→          }}
   461→        >
   462→          Loading gesture recognition...
   463→        </div>
   464→      )}
   465→    </main>
   466→  );
   467→}
   468→
   469→/* ── Recommendation sub-components (from main) ── */
   470→
   471→function OutfitsView({
   472→  greeting,
   473→  styleAnalysis,
   474→  outfits,
   475→  activeIndex,
   476→  onDotClick,
   477→}: {
   478→  greeting: string;
   479→  styleAnalysis: string;
   480→  outfits: Outfit[];
   481→  activeIndex: number;
   482→  onDotClick: (i: number) => void;
   483→}) {
   484→  const outfit = outfits[activeIndex];
   485→  if (!outfit) return null;
   486→
   487→  return (
   488→    <div
   489→      style={{
   490→        width: "100%",
   491→        display: "flex",
   492→        flexDirection: "column",
   493→        padding: 40,
   494→        boxSizing: "border-box",
   495→        color: "#fff",
   496→      }}
   497→    >
   498→      {/* Header */}
   499→      <div style={{ marginBottom: 24 }}>
   500→        <p style={{ fontSize: 22, fontWeight: 300, margin: 0 }}>{greeting}</p>
   501→        <p style={{ fontSize: 14, opacity: 0.6, marginTop: 6 }}>
   502→          {styleAnalysis}
   503→        </p>
   504→      </div>
   505→
   506→      {/* Outfit card */}
   507→      <div
   508→        style={{
   509→          display: "flex",
   510→          flexDirection: "column",
   511→          alignItems: "center",
   512→          justifyContent: "center",
   513→          gap: 20,
   514→        }}
   515→      >
   516→        <p
   517→          style={{
   518→            fontSize: 20,
   519→            fontWeight: 600,
   520→            letterSpacing: 1,
   521→            margin: 0,
   522→          }}
   523→        >
   524→          {outfit.outfit_name}
   525→        </p>
   526→
   527→        {/* Items row */}
   528→        <div
   529→          style={{
   530→            display: "flex",
   531→            gap: 24,
   532→            justifyContent: "center",
   533→            flexWrap: "wrap",
   534→          }}
   535→        >
   536→          {outfit.items.map((oi, idx) => (
   537→            <div
   538→              key={idx}
   539→              style={{
   540→                textAlign: "center",
   541→                width: 180,
   542→              }}
   543→            >
   544→              <div
   545→                style={{
   546→                  width: 180,
   547→                  height: 220,
   548→                  background: "#1a1a1a",
   549→                  borderRadius: 8,
   550→                  overflow: "hidden",
   551→                  marginBottom: 8,
   552→                }}
   553→              >
   554→                <img
   555→                  src={oi.item.cleaned_image_url ?? oi.item.flat_image_url ?? oi.item.image_url}
   556→                  alt={oi.item.title}
   557→                  style={{
   558→                    width: "100%",
   559→                    height: "100%",
   560→                    objectFit: "contain",
   561→                  }}
   562→                />
   563→              </div>
   564→              <p
   565→                style={{
   566→                  fontSize: 13,
   567→                  margin: 0,
   568→                  opacity: 0.9,
   569→                  whiteSpace: "nowrap",
   570→                  overflow: "hidden",
