    52→        () => avatar.talking(),
    53→        () => {
    54→          isProcessingQueueRef.current = false;
    55→          processQueue();
    56→        },
    57→      )
    58→      .catch(() => {
    59→        isProcessingQueueRef.current = false;
    60→        processQueue();
    61→      });
    62→  }, []);
    63→
    64→  const clearQueue = useCallback(() => {
    65→    speechQueueRef.current = [];
    66→    isProcessingQueueRef.current = false;
    67→  }, []);
    68→
    69→  // Cleanup on unmount
    70→  useEffect(() => {
