   103→    ttsRef.current?.stop();
   104→    avatarRef.current?.destroy();
   105→    avatarRef.current = null;
   106→    ttsRef.current = null;
   107→    setIsReady(false);
   108→    setIsSpeaking(false);
   109→  }, [clearQueue]);
   110→
   111→  const speak = useCallback(
   112→    (text: string) => {
   113→      if (!text.trim()) return;
   114→      console.log(
   115→        "[MemojiAvatar] Queued:",
   116→        text.slice(0, 60),
   117→        `(queue=${speechQueueRef.current.length})`,
   118→      );
   119→      speechQueueRef.current.push(text);
   120→      setIsSpeaking(true);
   121→      processQueue();
   122→    },
   123→    [processQueue],
   124→  );
   125→
   126→  const playScripted = useCallback(
   127→    async (videoPath: string) => {
   128→      if (!avatarRef.current) return;
   129→      // Stop any TTS and clear queue — scripted video has its own audio
   130→      clearQueue();
   131→      ttsRef.current?.stop();
   132→      setIsSpeaking(true);
   133→      await avatarRef.current.playScriptedVideo(videoPath);
   134→      setIsSpeaking(false);
   135→    },
   136→    [clearQueue],
   137→  );
   138→
   139→  const interrupt = useCallback(() => {
   140→    clearQueue();
   141→    ttsRef.current?.stop();
   142→    avatarRef.current?.idle();
   143→    setIsSpeaking(false);
   144→  }, [clearQueue]);
   145→
   146→  const setAvatarState = useCallback((state: AvatarState) => {
