/**
 * ElevenLabs TTS client — calls the backend proxy at /api/tts/speak.
 *
 * Falls back to browser SpeechSynthesis if the proxy is unavailable.
 */

export class ElevenLabsTTS {
  private apiUrl: string;
  private audio: HTMLAudioElement | null = null;
  private speaking = false;

  constructor(apiUrl: string) {
    this.apiUrl = apiUrl;
  }

  async speak(
    text: string,
    onStart?: () => void,
    onEnd?: () => void,
  ): Promise<void> {
    try {
      this.speaking = true;
      onStart?.();

      const resp = await fetch(`${this.apiUrl}/api/tts/speak`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text }),
      });

      if (!resp.ok) {
        throw new Error(`TTS proxy error: ${resp.status}`);
      }

      const blob = await resp.blob();
      const url = URL.createObjectURL(blob);

      await new Promise<void>((resolve) => {
        this.audio = new Audio(url);

        this.audio.onended = () => {
          this.speaking = false;
          URL.revokeObjectURL(url);
          onEnd?.();
          resolve();
        };

        this.audio.onerror = () => {
          this.speaking = false;
          URL.revokeObjectURL(url);
          onEnd?.();
          resolve();
        };

        this.audio.play().catch(() => {
          this.speaking = false;
          URL.revokeObjectURL(url);
          onEnd?.();
          resolve();
        });
      });
    } catch (err) {
      console.warn("[TTS] ElevenLabs proxy failed, falling back to browser TTS:", err);
      this.speaking = false;

      // Browser TTS fallback
      await this.browserFallback(text, onStart, onEnd);
    }
  }

  stop(): void {
    if (this.audio) {
      this.audio.pause();
      this.audio = null;
    }
    this.speaking = false;
    window.speechSynthesis?.cancel();
  }

  isSpeaking(): boolean {
    return this.speaking;
  }

  private browserFallback(
    text: string,
    onStart?: () => void,
    onEnd?: () => void,
  ): Promise<void> {
    return new Promise<void>((resolve) => {
      if (!window.speechSynthesis) {
        onEnd?.();
        resolve();
        return;
      }

      const utterance = new SpeechSynthesisUtterance(text);
      utterance.rate = 1.0;
      utterance.pitch = 1.1;

      utterance.onstart = () => {
        this.speaking = true;
        onStart?.();
      };

      utterance.onend = () => {
        this.speaking = false;
        onEnd?.();
        resolve();
      };

      utterance.onerror = () => {
        this.speaking = false;
        onEnd?.();
        resolve();
      };

      window.speechSynthesis.speak(utterance);
    });
  }
}

"""ElevenLabs TTS proxy endpoint.

Proxies text-to-speech requests to ElevenLabs API so the API key
stays server-side.  Returns audio/mpeg binary via StreamingResponse.
"""

import os

import httpx
from fastapi import APIRouter, HTTPException
from fastapi.responses import StreamingResponse
from pydantic import BaseModel, Field

router = APIRouter(prefix="/api/tts", tags=["tts"])

ELEVENLABS_API_URL = "https://api.elevenlabs.io/v1"


class SpeakRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=1000)


@router.post("/speak")
async def speak(body: SpeakRequest):
    """Convert text to speech via ElevenLabs and return audio/mpeg."""
    api_key = os.environ.get("ELEVENLABS_API_KEY")
    voice_id = os.environ.get("ELEVENLABS_VOICE_ID", "EXAVITQu4vr4xnSDxMaL")

    if not api_key:
        raise HTTPException(status_code=500, detail="ELEVENLABS_API_KEY not configured")

    async with httpx.AsyncClient() as client:
        try:
            resp = await client.post(
                f"{ELEVENLABS_API_URL}/text-to-speech/{voice_id}",
                headers={
                    "Accept": "audio/mpeg",
                    "Content-Type": "application/json",
                    "xi-api-key": api_key,
                },
                json={
                    "text": body.text,
                    "model_id": "eleven_multilingual_v2",
                    "voice_settings": {
                        "stability": 0.5,
                        "similarity_boost": 0.8,
                        "style": 0.5,
                        "use_speaker_boost": True,
                    },
                },
                timeout=30.0,
            )
        except httpx.RequestError as exc:
            raise HTTPException(
                status_code=502, detail=f"ElevenLabs request failed: {exc}"
            )

    if resp.status_code != 200:
        raise HTTPException(
            status_code=502,
            detail=f"ElevenLabs API error ({resp.status_code}): {resp.text[:200]}",
        )

    return StreamingResponse(
        iter([resp.content]),
        media_type="audio/mpeg",
        headers={"Content-Disposition": "inline"},
    )

