     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import type { RefObject } from "react";
     5→import { MemojiAvatar, type AvatarState } from "@/lib/memoji-avatar";
     6→import { ElevenLabsTTS } from "@/lib/elevenlabs-tts";
     7→
     8→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
     9→
    10→export interface UseMemojiAvatarReturn {
    11→  isReady: boolean;
    12→  isSpeaking: boolean;
    13→  startSession: () => Promise<void>;
    14→  stopSession: () => Promise<void>;
    15→  speak: (text: string) => void;
    16→  playScripted: (videoPath: string) => Promise<void>;
    17→  interrupt: () => void;
    18→  clearQueue: () => void;
    19→  setAvatarState: (state: AvatarState) => void;
    20→  containerRef: RefObject<HTMLDivElement | null>;
    21→}
    22→
    23→export function useMemojiAvatar(): UseMemojiAvatarReturn {
    24→  const [isReady, setIsReady] = useState(false);
    25→  const [isSpeaking, setIsSpeaking] = useState(false);
    26→  const containerRef = useRef<HTMLDivElement | null>(null);
    27→  const avatarRef = useRef<MemojiAvatar | null>(null);
    28→  const ttsRef = useRef<ElevenLabsTTS | null>(null);
    29→
    30→  // Speech queue
    31→  const speechQueueRef = useRef<string[]>([]);
    32→  const isProcessingQueueRef = useRef(false);
    33→
    34→  const processQueue = useCallback(() => {
    35→    if (isProcessingQueueRef.current || !avatarRef.current || !ttsRef.current) return;
    36→
    37→    const next = speechQueueRef.current.shift();
    38→    if (!next) {
    39→      setIsSpeaking(false);
    40→      avatarRef.current.idle();
    41→      return;
    42→    }
    43→
    44→    isProcessingQueueRef.current = true;
    45→    setIsSpeaking(true);
    46→    console.log("[MemojiAvatar] processQueue: speaking next sentence", {
    47→      sentence: next.slice(0, 80),
    48→      remaining: speechQueueRef.current.length,
    49→    });
    50→
    51→    const avatar = avatarRef.current;
    52→    ttsRef.current
    53→      .speak(
    54→        next,
    55→        () => avatar.talking(),
    56→        () => {
    57→          isProcessingQueueRef.current = false;
    58→          processQueue();
    59→        },
    60→      )
    61→      .catch(() => {
    62→        isProcessingQueueRef.current = false;
    63→        processQueue();
    64→      });
    65→  }, []);
    66→
    67→  const clearQueue = useCallback(() => {
    68→    speechQueueRef.current = [];
    69→    isProcessingQueueRef.current = false;
    70→  }, []);
    71→
    72→  // Cleanup on unmount
    73→  useEffect(() => {
    74→    return () => {
    75→      clearQueue();
    76→      ttsRef.current?.stop();
    77→      avatarRef.current?.destroy();
    78→      avatarRef.current = null;
    79→      ttsRef.current = null;
    80→    };
    81→  }, [clearQueue]);
    82→
    83→  const startSession = useCallback(async () => {
    84→    if (avatarRef.current) {
    85→      console.log("[MemojiAvatar] startSession: already initialized, skipping");
    86→      return;
    87→    }
    88→    const container = containerRef.current;
    89→    console.log("[MemojiAvatar] startSession: containerRef.current =", container ? "found" : "null");
    90→    if (!container) {
    91→      console.warn("[MemojiAvatar] No container ref — cannot start session");
    92→      return;
    93→    }
    94→
    95→    try {
    96→      const avatar = new MemojiAvatar(container);
    97→      await avatar.init();
    98→      avatarRef.current = avatar;
    99→
   100→      const tts = new ElevenLabsTTS(API_URL);
   101→      ttsRef.current = tts;
   102→
   103→      setIsReady(true);
   104→      console.log("[MemojiAvatar] Session started successfully");
   105→      // Drain any speech that queued before init completed
   106→      processQueue();
   107→    } catch (err) {
   108→      console.error("[MemojiAvatar] startSession failed:", err);
   109→    }
   110→  }, [processQueue]);
   111→
   112→  const stopSession = useCallback(async () => {
   113→    console.log("[MemojiAvatar] stopSession: cleaning up");
   114→    clearQueue();
   115→    ttsRef.current?.stop();
   116→    avatarRef.current?.destroy();
   117→    avatarRef.current = null;
   118→    ttsRef.current = null;
   119→    setIsReady(false);
   120→    setIsSpeaking(false);
   121→    console.log("[MemojiAvatar] stopSession: done");
   122→  }, [clearQueue]);
   123→
   124→  const speak = useCallback(
   125→    (text: string) => {
   126→      if (!text.trim()) return;
   127→      console.log(
   128→        "[MemojiAvatar] Queued:",
   129→        text.slice(0, 60),
   130→        `(queue=${speechQueueRef.current.length})`,
   131→      );
   132→      speechQueueRef.current.push(text);
   133→      setIsSpeaking(true);
   134→      processQueue();
   135→    },
   136→    [processQueue],
   137→  );
   138→
   139→  const playScripted = useCallback(
   140→    async (videoPath: string) => {
   141→      console.log("[MemojiAvatar] playScripted:", videoPath);
   142→      if (!avatarRef.current) {
   143→        console.warn("[MemojiAvatar] playScripted: avatar not initialized");
   144→        return;
   145→      }
   146→      // Stop any TTS and clear queue — scripted video has its own audio
   147→      clearQueue();
   148→      ttsRef.current?.stop();
   149→      setIsSpeaking(true);
   150→      await avatarRef.current.playScriptedVideo(videoPath);
   151→      setIsSpeaking(false);
   152→    },
   153→    [clearQueue],
   154→  );
   155→
   156→  const interrupt = useCallback(() => {
   157→    clearQueue();
   158→    ttsRef.current?.stop();
   159→    avatarRef.current?.idle();
   160→    setIsSpeaking(false);
   161→  }, [clearQueue]);
   162→
   163→  const setAvatarState = useCallback((state: AvatarState) => {
   164→    avatarRef.current?.setState(state);
   165→  }, []);
   166→
   167→  return {
   168→    isReady,
   169→    isSpeaking,
   170→    startSession,
   171→    stopSession,
   172→    speak,
   173→    playScripted,
   174→    interrupt,
   175→    clearQueue,
   176→    setAvatarState,
   177→    containerRef,
   178→  };
   179→}
