     1→/**
     2→ * Memoji avatar — manages looping video states and one-shot scripted videos.
     3→ *
     4→ * Ported from jenny/src/avatar.js.  Operates imperatively on a container
     5→ * HTMLDivElement provided by the React host (via ref).
     6→ */
     7→
     8→export type AvatarState =
     9→  | "idle"
    10→  | "thinking"
    11→  | "talking"
    12→  | "happy"
    13→  | "excited"
    14→  | "concerned";
    15→
    16→const STATES: AvatarState[] = [
    17→  "idle",
    18→  "thinking",
    19→  "talking",
    20→  "happy",
    21→  "excited",
    22→  "concerned",
    23→];
    24→
    25→export class MemojiAvatar {
    26→  private container: HTMLDivElement;
    27→  private videos: Partial<Record<AvatarState, HTMLVideoElement>> = {};
    28→  private currentVideo: HTMLVideoElement | null = null;
    29→  private scriptedVideo: HTMLVideoElement | null = null;
